import frappe
from frappe.utils import now,nowdate
from warrior.common import api_auth, api_response,get_employee_by_user, validate_employee_data,validate_method,add_ess_comment
from frappe.utils import flt,cint,get_url,getdate,pretty_date


ROLE_SALES = {"Sales Voice", "Sales Feild"}
ROLE_VRM_B2C = "VRM B2C"

MAPPING_DOCTYPE = "Order Mapping"
MAPPING_SO_FIELD = "sales_order"


# ------------------ Helpers ------------------

def mapped_sales_person(so_id):
    row = frappe.db.get_value(
        "Sales Team",
        {
            "parenttype": "Sales Order",
            "parent": so_id,
            "allocated_percentage": 100
        },
        "sales_person"
    )
    return row  # returns Sales Person name or None

def is_mapped(so_id):
    return bool(mapped_sales_person(so_id))


def dealer_tehsil(address):
    if not address:
        return None
    return (
        frappe.db.get_value("Address", address, "custom_tahshil"))


def sales_user_tehsils(user):
    emp = get_employee_by_user(user)
    if not emp:
        return None, "Employee not linked to this user"

    sp = frappe.db.get_value("Sales Person", {"employee": emp.get("name")}, "name")
    if not sp:
        return None, "Sales Person not mapped for this employee"
    tehsils=set(
        frappe.get_all("User Permission Tehsil", filters={"parent": sp}, pluck="tehsil")
    )
    if not tehsils:
        return None, "No tehsil assigned to Sales Person"

    return tehsils, None


def validate_order(so, user, roles):
    if is_mapped(so.name):
        return "Order already mapped"

    if not so.customer:
        return "Customer not found in Sales Order"

    cg = so.customer_group

    # Sales Voice / Sales Field
    if roles & ROLE_SALES:
        if cg != "Dealer":
            return "Sales users can map Dealer orders only"

        tehsils, err = sales_user_tehsils(user)
        if err:
            return err

        d_tehsil = dealer_tehsil(so.shipping_address_name)
        if not d_tehsil:
            return "Dealer address tehsil not found"

        if d_tehsil not in tehsils:
            return "Order tehsil is outside assigned area"

        return None

    # VRM B2C
    if ROLE_VRM_B2C in roles:
        if cg != "Farmer":
            return "VRM B2C users can map Farmer orders only"
        return None

    return "User not authorized to map orders"


def so_payload(so):
    # Customer basic
    customer_data = {
        "name": so.customer,
        "customer_group": so.customer_group,
        "mobile_no": so.contact_mobile,
        "dealer_tehsil": dealer_tehsil(so.shipping_address_name),
    }

    # Order items
    items = [
        {
            "item_code": d.item_code,
            "item_name": d.item_name,
            "qty": d.qty,
            "uom": d.uom,
            "rate": d.rate,
            "brand":d.brand,
            "amount": d.amount,
        }
        for d in so.items
    ]

    return {
        "sales_order_id": so.name,

        "customer": customer_data,

        "order": {
            "status": so.status,
            "transaction_date": so.transaction_date,
            "delivery_date": so.delivery_date,
            "grand_total": so.grand_total,
            "rounded_total": so.rounded_total,
            "total_qty": sum(d.qty for d in so.items),
        },

        "items": items,

        "mapping": {
            "already_mapped": bool(is_mapped(so.name)),
            "eligible_for_mapping": True,
        }
    }



# ------------------ APIs ------------------

@frappe.whitelist()
def get_sales_order_details(order_id):
    user = frappe.session.user

    if not order_id:
        return api_response(False, "order_id is required")

    if not frappe.db.exists("Sales Order", order_id):
        return api_response(False, "Invalid Sales Order ID")

    so = frappe.get_doc("Sales Order", order_id)
    roles = set(frappe.get_roles(user) or [])
    error = validate_order(so, user, roles)
    if error:
        return api_response(False, error)

    return api_response(True, "Eligible for mapping", so_payload(so))

@frappe.whitelist()
def map_order(order_id):
    user = frappe.session.user

    if not order_id:
        return api_response(False, "order_id is required")

    if not frappe.db.exists("Sales Order", order_id):
        return api_response(False, "Invalid Sales Order ID")

    so = frappe.get_doc("Sales Order", order_id)
    roles = set(frappe.get_roles(user) or [])
    error = validate_order(so, user, roles)
    if error:
        return api_response(False, error)

    # ✅ Resolve Sales Person from User -> Employee -> Sales Person
    emp = get_employee_by_user(user)
    if not emp:
        return api_response(False, "Employee not linked to this user")

    sales_person = frappe.db.get_value("Sales Person", {"employee": emp.get("name")}, "name")
    if not sales_person:
        return api_response(False, "Sales Person not mapped for this employee")

    # ✅ Update Sales Team (Allow on Submit)
    # Remove existing 100% row / same sales_person row to prevent duplicates
    so.set("sales_team", [
        r for r in (so.get("sales_team") or [])
        if not (r.sales_person == sales_person or (r.allocated_percentage or 0) == 100)
    ])

    so.append("sales_team", {
        "sales_person": sales_person,
        "allocated_percentage": 100,
    })

    # Allow on Submit table => saving works even when docstatus = 1
    so.flags.ignore_validate_update_after_submit = True
    so.save(ignore_permissions=True)

    return api_response(True, "Order mapped successfully")



def get_submitted_invoice_count(so_name):
    return frappe.db.sql("""
        SELECT COUNT(DISTINCT sii.parent)
        FROM `tabSales Invoice Item` sii
        JOIN `tabSales Invoice` si ON si.name = sii.parent
        WHERE sii.sales_order = %s AND si.docstatus = 1
    """, so_name)[0][0]
def format_address(address_id):
    address = frappe.db.get_value(
        "Address",
        address_id,
        [
            "address_line1",
            "address_line2",
            "custom_tahshil",
            "custom_district",
            "city",
            "state",
            "pincode"
        ],
        as_dict=True
    )

    if not address:
        return ""

    tahsil_name = frappe.db.get_value("Tahshil", address.get("custom_tahshil"), "tahshil") if address.get("custom_tahshil") else None
    district_name = frappe.db.get_value("District", address.get("custom_district"), "district_name") if address.get("custom_district") else None
    marketplace_name = frappe.db.get_value("Marketplace", address.get("city"), "marketplace_name") if address.get("marketplace") else None

    return ", ".join(
        str(v)
        for v in [
            address.get("address_line1"),
            address.get("address_line2"),
            marketplace_name,
            tahsil_name,
            district_name,
            address.get("state"),
            address.get("pincode"),
        ]
        if v
    )
@frappe.whitelist()
@validate_method(methods=["GET","POST"])
def get_order_from_list(
    search=None,
    dispatch_status=None,
    from_date=None,
    to_date=None,
    show_assign_order=False,
    page=1,
    page_size=20
):    
    try:

        filters = {
            "docstatus": ["!=", 2],
            # "order_type": "Shopping Cart"
            "shipping_address_name": ["is", "set"]
        }


        page = cint(page) or 1
        page_size = cint(page_size) or 20
        start = (page - 1) * page_size
        
        or_filters = []

        if search:
            or_filters = [
                ["Sales Order", "name", "like", f"%{search}%"],
                ["Sales Order", "customer_name", "like", f"{search}%"],
                ["Sales Order", "contact_mobile", "like", f"{search}%"],
            ]
        
        if dispatch_status:
            filters["custom_dispatch_status"] = dispatch_status

        data = frappe.db.sql("""
            SELECT DISTINCT dl.link_name
            FROM `tabAddress` a
            JOIN `tabDynamic Link` dl 
                ON dl.parent = a.name
                AND dl.link_doctype = 'Customer'
            WHERE a.custom_tahshil IN (
                SELECT for_value
                FROM `tabUser Permission`
                WHERE user = %s
                AND allow = 'Tahshil'
            )
            AND a.disabled = 0
        """, (frappe.session.user,))
        customers = [d[0] for d in data]
        # Convert to pluck list
        if data:
            filters["customer"]=["in",customers]
        if not from_date:
            from_date=nowdate()
        if not to_date:
            to_date=nowdate()
        static_from_date = "2025-04-01"
        if from_date and to_date:
            # override from_date if it's older
            if from_date < static_from_date:
                from_date = static_from_date

            filters["transaction_date"] = [
                "between",
                [f"{from_date} 00:00:00", f"{to_date} 23:59:59"]
            ]
        else:
            # if no date given, still enforce static filter
            filters["transaction_date"] = [">=", f"{static_from_date} 00:00:00"]
        if show_assign_order:
            employee = frappe.db.get_value(
                "Employee",
                {"user_id": frappe.session.user},
                "name"
            )

            sales_person = None
            if employee:
                sales_person = frappe.db.get_value(
                    "Sales Person",
                    {"employee": employee},
                    "name"
                )

            # ✅ APPLY SALES PERSON FILTER (IMPORTANT)
            if sales_person:
                sales_orders_by_sp = frappe.db.sql("""
                    SELECT DISTINCT st.parent
                    FROM `tabSales Team` st
                    INNER JOIN `tabSales Order` so
                        ON so.name = st.parent
                        AND st.parenttype = 'Sales Order'
                    WHERE st.sales_person = %s
                    AND so.docstatus != 2
                """, (sales_person,), as_list=True)

                sales_orders_by_sp = [d[0] for d in sales_orders_by_sp]

                if sales_orders_by_sp:
                    filters["name"] = ["in", sales_orders_by_sp]
                else:
                    # No assigned orders → return empty
                    return api_response(True, "No records found", {"data": []})
        total_records = frappe.db.count("Sales Order", filters)

        orders = frappe.get_list(
            "Sales Order",
            filters=filters,
            or_filters=or_filters,
            fields=[
                "name", "transaction_date", "creation","rounded_total",
                "grand_total", "advance_paid",
                "docstatus",
                "custom_payment_type",
                "custom_pay_on_proceed_order",
                "shipping_address_name",
                "customer_name",
                "customer",
                "customer_group",
                "contact_mobile",
                "custom_shipping_tehsil",
                "custom_dispatch_status",
                "custom_brand_ambassador",
                "owner"
            ],
            limit_start=start,
            limit_page_length=page_size,
            order_by="creation desc"
        )
       
        if not orders:
            return api_response(True, "No records found", {"data": []})

        order_ids = [o.name for o in orders]
        conditions = ""
        params = {}

        if customers:
            conditions = "AND document_name IN %(document_name)s"
            params["document_name"] = tuple(customers)

        tag_rows = frappe.db.sql(f"""
            SELECT document_name AS customer, tag
            FROM `tabTag Link`
            WHERE document_type = 'Customer'
            {conditions}
        """, params, as_dict=True)

        customer_tags = {}

        for r in tag_rows:
            customer_tags.setdefault(r["customer"], set()).add(r["tag"])
        mobiles = list({c.get("contact_mobile") for c in orders if c.get("contact_mobile")})

        if mobiles:
            analysts = frappe.get_all(
                "Analyst Data",
                filters={"mobile_no": ["in", mobiles]},
                fields=["mobile_no as mobile_number", "rating", "rank", "turnover"]
            )
            analyst_map = {a.mobile_number: a for a in analysts}
        # ---------------------------------------------------
        # 🔥 BULK DATA FETCH
        # ---------------------------------------------------
        def derive_order_type(cnt):
            if cnt == 0:
                return "Authorized"
            if cnt == 1:
                return "Single Ordering"
            return "Multiple Ordering"
        # PayU txns
        txn_map = frappe._dict()

        # 1️⃣ FIRST: Payment Link
        for r in frappe.get_all(
            "Payment Link",
            filters={"order_id": ["in", order_ids]},
            fields=["order_id", "transactionid"]
        ):
            if r.transactionid:
                txn_map.setdefault(r.order_id, []).append(r.transactionid)

        # 2️⃣ FALLBACK: Payment Gateway Transaction
        for r in frappe.get_all(
            "Payment Gateway Transaction",
            filters={"order_id": ["in", order_ids]},
            fields=["order_id", "txn_id"]
        ):
            if r.txn_id:
                txn_map.setdefault(r.order_id, []).append(r.txn_id)

        # Bank Transfer Unsettled Amount
        bank_unsettled = dict(frappe.db.sql("""
                SELECT
                    sales_order,
                    SUM(
                        CASE
                            WHEN transfer_type = 'Bank Transfer'
                                THEN IFNULL(amount, 0)
                            ELSE IFNULL(approved_amount, 0)
                        END
                    ) AS pending_amount
                FROM `tabBank Transfer Request`
                WHERE docstatus = 0
                AND status = 'Unsettled'
                GROUP BY sales_order
            """))

        # ---------------------------------------------------
        # 🧠 RESPONSE BUILD
        # ---------------------------------------------------

        TOLERANCE = 1.0
        result = []

        for so in orders:
            total = float(so.rounded_total or so.grand_total or 0)
            received = float(so.advance_paid or 0)
            pending = max(round(total - received, 2), 0)
            order_count = cint(frappe.db.count("Sales Order", {"customer": so.customer, "docstatus": ["!=", 2]}))
            order_type = derive_order_type(order_count)
            if pending <= TOLERANCE:
                pending = 0.0

            unsettled_amount = bank_unsettled.get(so.name, 0) or 0
            invoice_count=get_submitted_invoice_count(so.name)
            pending_amount = max(total - (received + unsettled_amount), 0)
            # Status
            if so.docstatus == 2 or (so.custom_dispatch_status or "").lower() == "cancelled":
                status = "Cancelled"
                pending = 0
            elif (so.custom_dispatch_status or "").lower() == "refunded":
                status = "Refunded"
                pending = 0
            elif (so.custom_dispatch_status or "").upper() not in ["PENDING PAYMENT", "FULLY PAID","MATERIAL SHORTAGE"]:
                status = so.custom_dispatch_status
                pending = 0 if status in ["PARTIALLY DELIVERED", "DELIVERED"] else pending
            elif (so.custom_dispatch_status or "").lower() == "material shortage":
                status = "Order Processing"

            elif received <= 0:
                status = "Pending"

            elif abs(total - received) <= TOLERANCE:
                status = "Fully Paid"
                pending = 0

            else:
                status = "Partially Paid"
            if (
                so.docstatus == 2
                or (so.status or "").lower() == "cancelled"
                or (so.custom_dispatch_status or "").lower() == "refunded"
            ):
                allowed_action = "none"
            else:
                if pending_amount == 0:
                    allowed_action = "none"      # fully paid
                elif pending_amount == total:
                    allowed_action = "cancel"    # nothing paid
                else:                # ✅ Partial Payment केस
                    if so.customer_group and so.customer_group.lower() == "dealer":
                        allowed_action = "map"   # dealer can map
                    else:
                        allowed_action = "none"  # farmer gets no action

            owner = so.owner or ""
            placed_by_type = "Sales"

            if owner == "Administrator":
                placed_by_type = "Admin"
            else:
                portal_customer = frappe.db.get_value("Portal User", {"user": owner}, "parent")
                if portal_customer:
                    placed_by_type = "Customer" if portal_customer == so.customer else "Sales"
                else:
                    placed_by_type = "Admin" if frappe.db.exists(
                        "Has Role", {"parent": owner, "role": "System Manager"}
                    ) else "Sales"
            analyst = analyst_map.get(so["contact_mobile"])
            turnover = flt(analyst.turnover) if analyst else 0
            result.append({
                "rating": analyst.rating if analyst else 0,
                "rank": analyst.rank if analyst else 0,
                "turnover": turnover,
                "order_id": so.name,
                "customer_id":so.customer,
                "customer_name": so.customer_name,
                "brand_ambassador": frappe.db.get_value("Brand Ambassador", {"customer": so.customer}, "name") or "",
                "shop_name": frappe.db.get_value("Delear Registration", {"mobile_number":so.contact_mobile}, "shop_name") or "",
                "date": so.transaction_date or so.creation,
                "total_amount": total,
                "received_amount": received,
                "pending_amount": pending,
                "unsettled_amount": unsettled_amount,
                "status": status,
                "address":format_address(so.shipping_address_name),
                "contact_mobile": so.contact_mobile,
                "order_type":order_type,
                "user_type": so.customer_group,
                "tags": list(customer_tags.get(so.customer, [])),
                "invoice_count": invoice_count,
                "place_by":"Placed by " + placed_by_type,
                "order_mapped": is_mapped(so.name),
                "allowed_action": allowed_action,
                "order_has_brand_ambassador": bool(so.custom_brand_ambassador),
                "sales_order_brand_ambassador": so.custom_brand_ambassador or ""
            })

        total_pages = (total_records + page_size - 1) // page_size
       
        return api_response(True, "Sales orders fetched", {
            "total": total_records,
            "page": page,
            "page_size": page_size,
            "total_pages": total_pages,
            "data": result
        })

    except Exception:
        frappe.log_error(frappe.get_traceback(), "get_order_from_list")
        return api_response(False, "Error fetching sales orders")
    
import frappe
from frappe.utils import flt

def _get_dispatched_invoice_names_for_so(so, invoice_names):
    """
    Return set of Sales Invoice names that are considered DISPATCHED.

    Rules:
    - If Upload LR Main exists for invoice => dispatched
    - If (Farmer + Indian Post transporter) and Indian Post Tracking Log exists
      with reference_name = invoice name => dispatched
    """
    dispatched = set()

    if not invoice_names:
        return dispatched

    # 1) LR uploaded (any transporter)
    lr_invoices = frappe.get_all(
        "Upload LR Main",
        filters={
            "sales_invoice": ["in", invoice_names],
            "docstatus": ["!=", 2],
        },
        pluck="sales_invoice",
    )
    dispatched.update(lr_invoices or [])

    # 2) Indian Post tracking log (only Farmer + Indian Post)
    is_farmer = (so.customer_group or "").strip().lower() == "farmer"

    transporter_name = ""
    if so.custom_transporter:
        transporter_name = (
            frappe.db.get_value("Supplier", so.custom_transporter, "supplier_name") or ""
        ).strip().lower()

    is_indian_post = "indian post" in transporter_name

    if is_farmer and is_indian_post and frappe.db.exists("DocType", "Indian Post Tracking Log"):
        ip_invoices = frappe.get_all(
            "Indian Post Tracking Log",
            filters={
                "reference_name": ["in", invoice_names],
                "docstatus": ["!=", 2],
            },
            pluck="reference_name",
        )
        dispatched.update(ip_invoices or [])

    return dispatched


def _get_fulfilment_details_from_sales_invoice(so):
    """
    Fulfilment based on Sales Invoice (submitted + update_stock=1),
    BUT qty is counted only when invoice is DISPATCHED:
      - Upload LR Main exists
      - OR (Farmer + Indian Post) => Indian Post Tracking Log exists (reference_name = invoice)
    """

    # Step 1: list all relevant invoices for this SO (update_stock only)
    invoice_rows = frappe.db.sql(
        """
        SELECT DISTINCT si.name
        FROM `tabSales Invoice Item` sii
        INNER JOIN `tabSales Invoice` si ON si.name = sii.parent
        WHERE
            si.docstatus = 1
            AND IFNULL(si.update_stock, 0) = 1
            AND (
                sii.sales_order = %s
                OR sii.so_detail IN (
                    SELECT soi.name FROM `tabSales Order Item` soi WHERE soi.parent = %s
                )
            )
        """,
        (so.name, so.name),
        as_dict=True
    )

    invoice_names = [r["name"] for r in invoice_rows]

    # No invoices => no dispatch
    if not invoice_names:
        overall_status = "Created" if so.docstatus == 0 else "Order Confirmed"
        return {
            "overall_status": overall_status,
            "fulfilment_percentage": 0.0,
            "dispatched_invoice_count": 0,
            "first_dispatch_date": None,
            "last_dispatch_date": None,
            "dispatch_timeline": [{"status": "Created", "date": so.creation}],
            "items": []
        }

    # Step 2: find dispatched invoices (LR OR IndianPost tracking as per rules)
    dispatched_invoices = _get_dispatched_invoice_names_for_so(so, invoice_names)

    if not dispatched_invoices:
        overall_status = "Created" if so.docstatus == 0 else "Order Confirmed"
        return {
            "overall_status": overall_status,
            "fulfilment_percentage": 0.0,
            "dispatched_invoice_count": 0,
            "first_dispatch_date": None,
            "last_dispatch_date": None,
            "dispatch_timeline": [{"status": "Created", "date": so.creation}],
            "items": [
                {
                    "item_code": i.item_code,
                    "item_name": i.item_name,
                    "ordered_qty": round(float(i.qty or 0), 3),
                    "dispatched_qty": 0.0,
                    "pending_qty": round(float(i.qty or 0), 3),
                    "status": "Pending"
                }
                for i in so.items
            ]
        }

    # Step 3: aggregate qty ONLY from dispatched invoices
    rows = frappe.db.sql(
        """
        SELECT
            sii.so_detail,
            sii.item_code,
            SUM(sii.qty) AS dispatched_qty,
            MIN(si.posting_date) AS first_dispatch_date,
            MAX(si.posting_date) AS last_dispatch_date,
            COUNT(DISTINCT si.name) AS invoice_count
        FROM `tabSales Invoice Item` sii
        INNER JOIN `tabSales Invoice` si ON si.name = sii.parent
        WHERE
            si.name IN %(dispatched_invoices)s
            AND si.docstatus = 1
            AND IFNULL(si.update_stock, 0) = 1
        GROUP BY sii.so_detail, sii.item_code
        """,
        {"dispatched_invoices": tuple(dispatched_invoices) or ("__never__",)},
        as_dict=True
    )

    dispatched_by_so_detail = {}
    dispatched_by_item_code = {}

    first_dispatch_date = None
    last_dispatch_date = None
    invoice_count = 0

    for r in rows:
        qty = float(r.get("dispatched_qty") or 0)

        if r.get("so_detail"):
            dispatched_by_so_detail[r["so_detail"]] = dispatched_by_so_detail.get(r["so_detail"], 0) + qty
        else:
            code = r.get("item_code")
            if code:
                dispatched_by_item_code[code] = dispatched_by_item_code.get(code, 0) + qty

        if r.get("first_dispatch_date"):
            first_dispatch_date = r["first_dispatch_date"] if not first_dispatch_date else min(first_dispatch_date, r["first_dispatch_date"])

        if r.get("last_dispatch_date"):
            last_dispatch_date = r["last_dispatch_date"] if not last_dispatch_date else max(last_dispatch_date, r["last_dispatch_date"])

        invoice_count += int(r.get("invoice_count") or 0)

    # Step 4: per item fulfilment
    total_ordered = 0.0
    total_dispatched = 0.0
    item_fulfilment = []

    for soi in so.items:
        ordered_qty = float(soi.qty or 0)

        dispatched_qty = float(dispatched_by_so_detail.get(soi.name, 0))
        if dispatched_qty == 0:
            dispatched_qty = float(dispatched_by_item_code.get(soi.item_code, 0))

        dispatched_qty = min(dispatched_qty, ordered_qty)
        pending_qty = max(ordered_qty - dispatched_qty, 0)

        total_ordered += ordered_qty
        total_dispatched += dispatched_qty

        if dispatched_qty <= 0:
            line_status = "Pending"
        elif dispatched_qty < ordered_qty:
            line_status = "Partially Dispatched"
        else:
            line_status = "Dispatched"

        item_fulfilment.append({
            "item_code": soi.item_code,
            "item_name": soi.item_name,
            "ordered_qty": round(ordered_qty, 3),
            "dispatched_qty": round(dispatched_qty, 3),
            "pending_qty": round(pending_qty, 3),
            "status": line_status
        })

    fulfilment_percentage = (total_dispatched / total_ordered * 100) if total_ordered else 0

    # Overall status based on dispatched qty
    if so.docstatus == 0:
        overall_status = "Created"
    elif total_dispatched <= 0:
        overall_status = "Order Confirmed"
    elif total_dispatched < total_ordered:
        overall_status = "Partially Dispatched"
    else:
        overall_status = "Dispatched"

    # Timeline
    timeline = [{"status": "Created", "date": so.creation}]
    if first_dispatch_date:
        timeline.append({"status": "First Dispatch", "date": first_dispatch_date})
    if overall_status == "Dispatched" and last_dispatch_date:
        timeline.append({"status": "Fully Dispatched", "date": last_dispatch_date})

    return {
        "overall_status": overall_status,
        "fulfilment_percentage": round(fulfilment_percentage, 2),
        "dispatched_invoice_count": len(dispatched_invoices),
        "invoice_count_with_update_stock": invoice_count,
        "first_dispatch_date": first_dispatch_date,
        "last_dispatch_date": last_dispatch_date,
        "dispatch_timeline": timeline,
        "items": item_fulfilment
    }

def get_si_dispatch_status_map(so_name):
    """
    Fetch latest Sales Invoice dispatch status for all SO items in one query
    """

    data = frappe.db.sql("""
        SELECT
            sii.so_detail,
            si.custom_dispatch_status,
            si.posting_date,
            si.posting_time
        FROM `tabSales Invoice Item` sii
        JOIN `tabSales Invoice` si ON si.name = sii.parent
        WHERE sii.sales_order = %s
          AND si.docstatus = 1
          AND IFNULL(si.is_return, 0) = 0
        ORDER BY
            sii.so_detail,
            si.posting_date DESC,
            si.posting_time DESC
    """, so_name, as_dict=True)

    status_map = {}

    for row in data:
        # Keep only latest per item
        if row.so_detail not in status_map and row.custom_dispatch_status:
            status_map[row.so_detail] = row.custom_dispatch_status

    return status_map


def get_sales_order_item_status(so, item, si_status_map=None):
    """
    Returns the status of a single Sales Order item.
    
    Priority:
    1. REFUNDED (custom_item_status on item)
    2. Sales Invoice Dispatch Status (if item exists in invoice)
    3. Sales Order Dispatch Status
    """
    # Build Sales Invoice status map if not provided
    if si_status_map is None:
        si_items = frappe.db.get_all(
            "Sales Invoice Item",
            filters={"sales_order": so.name},
            fields=["sales_order_item", "parent as invoice_name"]
        )

        si_status_map = {}
        if si_items:
            invoice_names = list(set([si["invoice_name"] for si in si_items]))
            invoice_status_map = frappe.db.get_all(
                "Sales Invoice",
                filters={"name": ["in", invoice_names]},
                fields=["name", "custom_dispatch_status"]
            )
            invoice_status_lookup = {inv["name"]: inv["custom_dispatch_status"] for inv in invoice_status_map}
            for si in si_items:
                si_status_map[si["sales_order_item"]] = invoice_status_lookup.get(si["invoice_name"])

    # 1. REFUNDED
    if item.get("custom_item_status") == "REFUNDED":
        return "REFUNDED"
    # 2. Sales Invoice status
    elif si_status_map.get(item.name):
        return si_status_map.get(item.name)
    # 3. Fallback → Sales Order status
    else:
        return so.get("custom_dispatch_status") or so.status


@frappe.whitelist()
@validate_method(methods=["GET","POST"])
def get_order_details():
    import json

    try:
        def _fmt_date(value):
            if not value:
                return ""
            try:
                return frappe.utils.formatdate(value, "dd-mm-yyyy")
            except Exception:
                return str(value)

        def _fmt_datetime(value):
            if not value:
                return ""
            try:
                return frappe.utils.format_datetime(value, "dd-MM-yyyy HH:mm:ss")
            except Exception:
                return str(value)
        body = json.loads(frappe.request.data or "{}")
        order_id = body.get("order_id")

        if not order_id:
            return api_response(False, "Order ID is required")

        if not frappe.db.exists("Sales Order", order_id):
            return api_response(False, "Invalid Order ID")


        so = frappe.get_doc("Sales Order", order_id)

        # ---------------- FULFILMENT (FROM SALES INVOICE) ----------------
        fulfilment_details = _get_fulfilment_details_from_sales_invoice(so)
        customer_group_normalized = (so.customer_group or "").strip().lower()
        transporter_label = ""
        if so.custom_transporter:
            transporter_label = (
                frappe.db.get_value("Supplier", so.custom_transporter, "supplier_name")
                or so.custom_transporter
                or ""
            )
        transporter_name_normalized = transporter_label.strip().lower()
        is_farmer = customer_group_normalized == "farmer"
        is_indian_post = "indian post" in transporter_name_normalized

        # ---------------- ORDER SUMMARY ----------------
        order_summary = {
            "order_created_on": so.creation,  # ✅ added
            "order_date": so.transaction_date,
            "customer_name": so.customer_name,
             "customer_group": so.customer_group,
            "shop_name": frappe.db.get_value("Delear Registration", {"mobile_number":so.contact_mobile}, "shop_name") or "",
            "payment_status": so.custom_payment_status,
            "brand_ambassador":so.custom_brand_ambassador,
            "contact_mobile": so.contact_mobile,
            "order_status": so.custom_dispatch_status,  # your custom
            "fulfilment_type": so.set_warehouse,
            "transporter_name": frappe.db.get_value("Supplier", so.custom_transporter, "supplier_name") or "",
            "order_id": so.name,
            "order_amount": float(so.rounded_total or so.grand_total),
            "total_items": sum(flt(i.qty) for i in so.items),
            "discount_received": float(so.discount_amount or 0),
            "coupon_code": so.coupon_code or "",
            "coupon_percentage": 0
        }

        address_data = frappe.db.get_value(
            "Address",
            so.shipping_address_name,
            [
                "address_line1",
                "city",
                "state",
                "pincode",
                "country",
                "custom_tahshil",
                "custom_district"
            ],
            as_dict=True
        ) or {}
        AddressLine1 = address_data.get("address_line1", "")
        city = address_data.get("city", "")
        state = address_data.get("state", "")
        pincode = address_data.get("pincode", "")
        country = address_data.get("country", "")
        tahsil_name = frappe.db.get_value(
            "Tahshil",
            address_data.get("custom_tahshil"),
            "tahshil"
        ) if address_data.get("custom_tahshil") else None

        district_name = frappe.db.get_value(
            "District",
            address_data.get("custom_district"),
            "district_name"
        ) if address_data.get("custom_district") else None

        marketplace_name = frappe.db.get_value(
            "Marketplace",
            city,
            "marketplace_name"
        ) if city else None
        # ---------------- TRANSACTIONS ----------------
        txnid = []

        # Payment Link txn IDs
        txnid.extend(
            frappe.get_all(
                "Payment Link",
                filters={"order_id": so.name},
                pluck="transactionid"
            )
        )

        # Payment Gateway Transaction txn IDs
        txnid.extend(
            frappe.get_all(
                "Payment Gateway Transaction",
                filters={"order_id": so.name},
                pluck="txn_id"
            )
        )

        # Optional: remove duplicates
        txnid = list(set(txnid))

        transactions = frappe.get_all(
            "PayU Response",
            filters={"txnid": ["IN",txnid]},
            fields=["status", "amount", "mode", "txnid", "createdat","addedon"]
        )
        bank_transfers= frappe.get_all(
            "Bank Transfer Request",
            filters={"sales_order": so.name, "docstatus": ["!=",2]},  # approved
            fields=["amount", "name", "approved_on as creation","status","approved_amount","transfer_type"],
        )
        rupify_transfers= frappe.get_all(
            "Rupifi Webhook Log",
            filters={"order_id": so.name},
            fields=["merchant_payment_ref_id", "amount_value", "createdat","status"]
        )
        van_transactions= frappe.get_all(
            "Van Transactions",
            filters={"sales_order": so.name},
            fields=["name", "transaction_amount", "created_at","transaction_status"]
        )
         # -----------------------------------------
        # ✅ ADD THIS: JOURNAL ENTRY
        # -----------------------------------------
        invoices = list(set(frappe.get_all(
            "Sales Invoice Item",
            filters={
                "sales_order": so.name
            },
            pluck="parent"
        )))
        je_entries = frappe.db.sql("""
            SELECT
                je.name,
                je.posting_date,
                je.remark,
                SUM(jea.debit) as debit,
                SUM(jea.credit) as credit
            FROM `tabJournal Entry` je
            JOIN `tabJournal Entry Account` jea ON je.name = jea.parent
            WHERE je.docstatus = 1
            AND jea.reference_type IN ('Sales Order', 'Sales Invoice')
            AND (
                (jea.reference_type = 'Sales Order' AND jea.reference_name = %(so)s)
                OR
                (jea.reference_type = 'Sales Invoice' AND jea.reference_name IN %(invoices)s)
            )
            AND je.mode_of_payment = "adjusted from one order to another"
            GROUP BY je.name
        """, {
            "so": so.name,
            "invoices": tuple(invoices or [""])
        }, as_dict=True)


        transaction_data = []
        for tr in transactions:
            transaction_data.append({
                "amount": float(tr.amount),
                "mode_of_payment": "UPI",
                "transaction_id": tr.txnid,
                "date": frappe.utils.format_datetime(tr.createdat) or frappe.utils.format_datetime(tr.addedon),
                "status": tr.status
            })
        for bt in bank_transfers:
            transaction_data.append({
                "amount": float(bt.amount) if bt.status=='Unsettled' and bt.transfer_type == "Bank Transfer" else float(bt.approved_amount),
                "mode_of_payment": bt.transfer_type,
                "transaction_id": bt.name,
                "date": frappe.utils.format_datetime(bt.creation),
                "status": bt.status,
            })
        for rt in rupify_transfers:
            transaction_data.append({
                "amount": float(rt.amount_value),
                "mode_of_payment": "Shoption Credit",
                "transaction_id": rt.merchant_payment_ref_id,
                "date": frappe.utils.format_datetime(rt.createdat),
                "status":"Success" if rt.status=="CAPTURED" else "Failed",
            })
        for vt in van_transactions:
            transaction_data.append({
                "amount": float(vt.transaction_amount),
                "mode_of_payment": "Van Transaction",
                "transaction_id": vt.name,
                "date": frappe.utils.format_datetime(vt.created_at),
                "status": vt.transaction_status,
            })
        for je in je_entries:
            transaction_data.append({
                "amount": float(je.credit or 0),  # ✅ show value
                "mode_of_payment": "Map From Another Order",
                "transaction_id": je.name,
                "date": frappe.utils.formatdate(je.posting_date),
                "status": "Completed",
                "remark": je.remark
            })
        # ---------------- FINANCIAL ----------------
        received = 0

        for tr in transaction_data:
            status = (tr.get("status") or "").lower()
            amount = float(tr.get("amount") or 0)

            # ✅ Only count successful transactions
            if status in ["success", "completed", "captured","approved"]:
                received += amount


        # -----------------------------
        # ✅ BANK PENDING (ONLY DRAFT / PENDING)
        # -----------------------------
        bank_paid = frappe.db.sql("""
            SELECT SUM(amount)
            FROM `tabBank Transfer Request`
            WHERE sales_order = %s
            AND docstatus = 0 AND status = 'Unsettled'
        """, so.name)[0][0] or 0

        si_status_map = get_si_dispatch_status_map(so.name)
        # -----------------------------
        # ✅ FINAL PENDING
        # -----------------------------
        total = float(so.rounded_total or so.grand_total)
        pending_amount = max(total - (received + bank_paid), 0)

        # ✅ Handle rounding difference
        if abs(pending_amount) < 1:
            pending_amount = 0

        # Cancelled / Refunded
        if (
            so.docstatus == 2
            or (so.status or "").lower() == "cancelled"
            or (so.custom_dispatch_status or "").lower() in ["refunded", "cancelled","partially delivered","delivered"] 
        ):
            allowed_action = "none"

        else:
            if pending_amount == 0:
                allowed_action = "none"      # fully paid

            elif pending_amount == total:
                allowed_action = "cancel"    # no payment

            else:
                # ✅ Partial Payment केस
                if customer_group_normalized == "dealer":
                    allowed_action = "map"   # dealer can map
                else:
                    allowed_action = "none"  # farmer gets no action


        order_summary["allowed_action"] = allowed_action
        order_summary["received"] = received         
        # ---------------- INVOICES ----------------
        invoices = frappe.get_all(
            "Sales Invoice Item",
            filters={"sales_order": so.name,"docstatus": ["=", 1]},
            fields=["parent"],
            distinct=True
        )
        invoice_names = [inv.parent for inv in invoices if inv.parent]

        def _build_print_url(doctype, name, print_format=""):
            if not doctype or not name:
                return ""
            query = (
                f"doctype={quote(doctype)}"
                f"&name={quote(name)}"
                "&trigger_print=1"
                "&no_letterhead=1"
                "&_lang=en"
            )
            if print_format:
                query += f"&format={quote(print_format)}"
            return get_url(f"/printview?{query}")

        sales_invoice_print_format = f"{get_url()}/api/method/frappe.utils.print_format.download_pdf?doctype=Sales%20Invoice&name=SINV-0001&format=Sales%20Invoice%20New"

        lr_list_by_invoice = {}
        if invoice_names and frappe.db.exists("DocType", "Upload LR Main"):
            lr_rows = frappe.get_all(
                "Upload LR Main",
                filters={"sales_invoice": ["in", invoice_names], "docstatus": ["!=", 2]},
                fields=[
                    "name", "sales_invoice", "transporter", "transporter_name",
                    "tracking_id", "lr_copy", "payment_status","customer_delivery_date","total_charges",
                    "estimeted_arrival_time", "creation", "no_of_boxes", "freight_amount"
                ],
                order_by="creation desc"
            )
            
            for lr in lr_rows:
                if lr.sales_invoice:
                    lr_list_by_invoice.setdefault(lr.sales_invoice, []).append(lr)

        ip_list_by_invoice = {}
        if (
            invoice_names
            and frappe.db.exists("DocType", "Indian Post Tracking Log")
        ):
            ip_rows = frappe.get_all(
                "Indian Post Tracking Log",
                filters={
                    "reference_type": "Sales Invoice",
                    "reference_name": ["in", invoice_names],
                    "docstatus": ["!=", 2],
                    "is_cancelled": 0,
                },
                fields=[
                    "name", "reference_name", "transporter", "tracking_id",
                    "payment_status", "estimeted_arrival_time", "created_at", "creation",
                    "no_of_boxes", "amount","length_cm","breadth_cm","height_cm","total_weight"
                ],
                order_by="creation desc"
            )
            for ip in ip_rows:
                if ip.reference_name:
                    ip_list_by_invoice.setdefault(ip.reference_name, []).append(ip)

        invoice_list = []
        for inv in invoices:
            si = frappe.get_doc("Sales Invoice", inv.parent)
            lr_list = lr_list_by_invoice.get(si.name, [])
            ip_list = ip_list_by_invoice.get(si.name, [])
            lr_entries = []
            ip_entries = []

            for lr in lr_list:
                lr_entries.append({
                    "lr_number": lr.get("name") or "",
                    "transporter": lr.get("transporter") or "",
                    "transporter_name": frappe.db.get_value("Supplier", lr.get("transporter"), "supplier_name") or "",
                    "tracking_id": lr.get("tracking_id") or "",
                    "lr_copy": get_url(lr.get("lr_copy")) if lr.get("lr_copy") else "",
                    "payment_status": lr.get("payment_status") or "",
                    "estimated_arrival_time": _fmt_datetime(lr.get("estimeted_arrival_time") or ""),
                    "no_of_boxes": float(lr.get("no_of_boxes") or 0),
                    "amount": float(lr.get("freight_amount") or 0),
                    "charges": float(lr.get("total_charges") or 0),
                    "created_at": _fmt_datetime(lr.get("creation") or ""),
                })

            for ip in ip_list:
                ip_entries.append({
                    "log_id": ip.get("name") or "",
                    "transporter": ip.get("transporter") or "",
                    "transporter_name": frappe.db.get_value("Supplier", ip.get("transporter"), "supplier_name") or "",
                    "tracking_id": ip.get("tracking_id") or "",
                    "payment_status": ip.get("payment_status") or "",
                    "estimated_arrival_time": _fmt_datetime(ip.get("estimeted_arrival_time") or ""),
                    "no_of_boxes": float(ip.get("no_of_boxes") or 0),
                    "amount": float(ip.get("amount") or 0),
                    "charges": float(ip.get("amount") or 0),
                    "created_at": _fmt_datetime(ip.get("created_at") or ip.get("creation") or ""),
                    "print_url": f"{get_url()}{frappe.db.get_value('File', {'attached_to_doctype': 'Indian Post Tracking Log', 'attached_to_name': ip.get('name')}, 'file_url')}" or "",
                })

            lr_and_stickers = []
            for lr_entry in lr_entries:
                lr_and_stickers.append({
                    "type": "lr",
                    "entry_id": lr_entry.get("lr_number") or "",
                    "transporter": lr_entry.get("transporter") or "",
                    "transporter_name": frappe.db.get_value("Supplier", lr_entry.get("transporter"), "supplier_name") or "",
                    "tracking_id": lr_entry.get("tracking_id") or "",
                    "payment_status": lr_entry.get("payment_status") or "",
                    "estimated_arrival_time": lr_entry.get("estimated_arrival_time") or "",
                    "no_of_boxes": float(lr_entry.get("no_of_boxes") or 0),
                    "amount": float(lr_entry.get("amount") or 0),
                    "charges": float(lr_entry.get("charges") or 0),
                    "document_url": lr_entry.get("lr_copy") or "",
                    "created_at": lr_entry.get("created_at") or "",
                    "print_url": "",
                })
            for ip_entry in ip_entries:
                lr_and_stickers.append({
                    "type": "sticker",
                    "entry_id": ip_entry.get("log_id") or "",
                    "transporter": ip_entry.get("transporter") or "",
                    "transporter_name": frappe.db.get_value("Supplier", ip_entry.get("transporter"), "supplier_name") or "",
                    "tracking_id": ip_entry.get("tracking_id") or "",
                    "payment_status": ip_entry.get("payment_status") or "",
                    "estimated_arrival_time": ip_entry.get("estimated_arrival_time") or "",
                    "no_of_boxes": float(ip_entry.get("no_of_boxes") or 0),
                    "amount": float(ip_entry.get("amount") or 0),
                    "charges": float(ip_entry.get("charges") or 0),
                    "document_url": ip_entry.get("print_url") or "",
                    "created_at": ip_entry.get("created_at") or "",
                    "print_url": ip_entry.get("print_url") or "",
                })

            if is_farmer and is_indian_post:
                selected_source = "indian_post_tracking_log"
                selected_entries = ip_entries
            elif not is_farmer and not is_indian_post:
                selected_source = "upload_lr_main"
                selected_entries = lr_entries
            elif ip_entries and not lr_entries:
                selected_source = "indian_post_tracking_log"
                selected_entries = ip_entries
            elif lr_entries and not ip_entries:
                selected_source = "upload_lr_main"
                selected_entries = lr_entries
            else:
                selected_source = "both"
                selected_entries = lr_entries + ip_entries

            total_no_of_boxes = sum(x["no_of_boxes"] for x in selected_entries)
            total_transport_amount = sum(x["amount"] for x in selected_entries)

            invoice_list.append({
                "invoice_id": si.name,
                "invoice_date": _fmt_date(si.posting_date),
                "amount": float(si.rounded_total or si.grand_total or 0),
                "lr_number": frappe.db.get_value("Upload LR Main", {"sales_invoice": si.name}, "name") or "",
                "dispatch_date": frappe.db.get_value("Upload LR Main", {"sales_invoice": si.name}, "creation") or "",
                "update_stock": int(getattr(si, "update_stock", 0)),
                "status": si.status,
                "dispatch_status": si.custom_dispatch_status or "",
                "no_of_boxes": float(total_no_of_boxes or 0),
                "transport_amount": float(total_transport_amount or 0),
                "charges": float(total_transport_amount or 0),
                "sales_invoice_print_url":sales_invoice_print_format.replace("SINV-0001", si.name),
                "selected_source": selected_source,
                "selected_transport_entries": selected_entries,
                "lr_and_stickers": lr_and_stickers,
            })

        # ---------------- DISPATCH DETAILS ----------------
        deliveries = frappe.get_all(
            "Delivery Note Item",
            filters={"against_sales_order": so.name},
            fields=["parent"],
            distinct=True
        )

        dispatch_list = []
        for d in deliveries:
            dn = frappe.get_doc("Delivery Note", d.parent)
            dispatch_list.append({
                "dispatch_id": dn.name,
                "delivery_slip": dn.name,
                "date": _fmt_date(dn.posting_date),
                "status": dn.status
            })

        delivery_slips = []
        if invoice_names and frappe.db.exists("DocType", "Shipment"):
            shipment_meta = frappe.get_meta("Shipment")
            shipment_fields = ["name", "creation", "docstatus"]
            if shipment_meta.has_field("status"):
                shipment_fields.append("status")
            if shipment_meta.has_field("tracking_number"):
                shipment_fields.append("tracking_number")
            if shipment_meta.has_field("carrier"):
                shipment_fields.append("carrier")
            if shipment_meta.has_field("custom_delivery_conformation_recording"):
                shipment_fields.append("custom_delivery_conformation_recording")

            shipment_rows = frappe.get_all(
                "Shipment",
                filters={
                    "custom_sales_invoice": ["in", invoice_names],
                    "docstatus": ["!=", 2],
                },
                fields=shipment_fields,
                order_by="creation desc"
            )

            for sh in shipment_rows:
                delivery_slips.append({
                    "delivery_slip_id": sh.name,
                    "date": _fmt_datetime(sh.creation),
                    "status": sh.get("status") or "",
                    "tracking_number": sh.get("tracking_number") or "",
                    "carrier": sh.get("carrier") or "",
                    "delivery_confirmation_recording": get_url(sh.get("custom_delivery_conformation_recording")) or "",
                })

        # ---------------- SHIPMENT ITEMS ----------------
        shipment_items = []
        for item in so.items:
            shipment_items.append({
                "item_code": item.item_code,
                "item_name": item.item_name,
                "image":frappe.db.get_value("Item",item.item_code,"custom_image_1"),
                "qty": float(item.qty),
                "rate": float(item.rate),
                "total": float(item.amount),
                "status": get_sales_order_item_status(so, item, si_status_map)
            })
        complaints = frappe.get_all(
            "Raise a Complaint",
            filters={"order_id": so.name},
            fields=["name", "subject", "description", "raised_on", "status","complaint_type"]
        ) or []
        # ---------------- ITEMS (YOUR OLD LIST) ----------------
        items = []
        for item in so.items:
            items.append({
                "item_code": item.item_code,
                "item_name": item.item_name,
                "image": frappe.db.get_value("Item", item.item_code, "custom_image_1"),
                "qty": float(item.qty or 0),
                "rate": float(item.rate or 0),
                "total": float(item.amount or 0)
            })

        # ---------------- FINAL RESPONSE ----------------
        response = {
            "order_summary": order_summary,
            "fulfilment_details": fulfilment_details,  # ✅ added
            "transactions": transaction_data,
            "invoices": invoice_list,
            "invoice_count": len(invoice_list),
            "dispatch_details": dispatch_list,
            "shipment": {
                "transporter_name": frappe.db.get_value("Supplier", so.custom_transporter, "supplier_name") if so.custom_transporter else "",
                "status": so.custom_dispatch_status or "",
                "date": _fmt_date(so.transaction_date),
                "items": shipment_items,
                "delivery_slips": delivery_slips
            },
            "financial_summary": {
                "total_amount": total,
                "amount_received": received,
                "amount_pending": pending_amount,
                "unsettled_amount": float(bank_paid)
            },
            "items": items,
            "shipping_address_details": {
                "address_line_1": AddressLine1,
                "city": city,
                "state": state,
                "pincode": pincode,
                "country": country,
                "tahsil": tahsil_name,
                "district": district_name,
                "marketplace": marketplace_name
            },
            "complaints_count": len(complaints),
            "complaints": complaints
        }

        return api_response(True, "Order details fetched", response)

    except Exception:
        frappe.log_error(frappe.get_traceback(), "get_order_details")
        return api_response(False, "Failed to fetch order details")


