@frappe.whitelist()
@validate_method(methods=["POST"])
def map_brand_ambassador(sales_order, brand_ambassador):
    try:
        if not sales_order or not brand_ambassador:
            return api_response(False, "Sales Order and Brand Ambassador are required")
        if not frappe.db.exists("Sales Order", sales_order):
            return api_response(False, "Invalid Sales Order")
        if not frappe.db.exists("Brand Ambassador", brand_ambassador):
            return api_response(False, "Invalid Brand Ambassador")
        so=frappe.db.get_value("Sales Order",sales_order,["custom_brand_ambassador","customer_group","customer"],as_dict=True)
        if so.custom_brand_ambassador:
            return api_response(False, "Brand Ambassador already mapped for this Sales Order")
        if so.customer_group.strip().lower()!="farmer":
            return api_response(False, "Brand Ambassador can only be mapped for farmers")
        frappe.db.set_value("Sales Order", sales_order, "custom_brand_ambassador", brand_ambassador)
        return api_response(True, "Brand Ambassador mapped successfully")
    except Exception:
        frappe.log_error(frappe.get_traceback(), "map_brand_ambassador_error")
        return api_response(False, "Failed to map Brand Ambassador")
    

@frappe.whitelist()
@validate_method(methods=["GET"])
def stock_report(
    warehouse,
    item_code=None,
    item_name=None,
    page=1,
    page_size=20
):
    try:

        # ✅ Mandatory warehouse
        if not warehouse:
            return api_response(False, "Warehouse is required")

        conditions = []
        params = {}

        conditions.append("bin.actual_qty > 0")
        conditions.append("bin.warehouse = %(warehouse)s")
        params["warehouse"] = warehouse

        if item_code:
            conditions.append("bin.item_code = %(item_code)s")
            params["item_code"] = item_code

        if item_name:
            conditions.append("i.item_name LIKE %(item_name)s")
            params["item_name"] = f"%{item_name}%"

        where_clause = " AND ".join(conditions)
        where_clause = "WHERE " + where_clause

        # -------------------------
        # Pagination
        # -------------------------

        page = int(page or 1)
        page_size = int(page_size or 20)

        if page < 1:
            page = 1

        if page_size < 1:
            page_size = 20

        start = (page - 1) * page_size

        # -------------------------
        # Total Records
        # -------------------------

        total_records = frappe.db.sql(f"""
            SELECT COUNT(*) as count
            FROM `tabBin` bin
            LEFT JOIN `tabItem` i ON i.name = bin.item_code
            LEFT JOIN `tabBrand` b ON b.name = i.brand
            {where_clause}
        """, params, as_dict=True)[0].count

        total_pages = (
            (total_records + page_size - 1) // page_size
            if total_records else 0
        )

        # -------------------------
        # Fetch Data
        # -------------------------

        data = frappe.db.sql(f"""
            SELECT
                i.brand AS brand_id,
                b.brand AS brand_name,
                i.name AS item_code,
                i.item_name AS item_name,
                bin.warehouse,
                bin.actual_qty AS warehouse_qty,
                bin.reserved_stock AS reserved_qty,
                (bin.actual_qty - bin.reserved_stock) AS available_qty
            FROM `tabBin` bin
            LEFT JOIN `tabItem` i ON i.name = bin.item_code
            LEFT JOIN `tabBrand` b ON b.name = i.brand
            {where_clause}
            ORDER BY i.item_name ASC
            LIMIT %(start)s, %(page_size)s
        """, {
            **params,
            "start": start,
            "page_size": page_size
        }, as_dict=True)

        # -------------------------
        # Response
        # -------------------------

        return api_response(
            True,
            "Stock report fetched",
            {
                "total": total_records,
                "page": page,
                "page_size": page_size,
                "total_pages": total_pages,
                "data": data
            }
        )

    except Exception:

        frappe.log_error(
            frappe.get_traceback(),
            "stock_report_error"
        )

        return api_response(
            False,
            "Failed to fetch stock report"
        )

@frappe.whitelist()
def get_indian_post_tracking_ids():

    try:

        # -------------------------
        # USER -> EMPLOYEE
        # -------------------------

        user = frappe.session.user

        employee_id = frappe.db.get_value(
            "Employee",
            {"user_id": user},
            "name"
        )

        if not employee_id:
            return api_response(
                False,
                "Employee not found for user"
            )

        # -------------------------
        # EMPLOYEE -> SALES PERSON
        # -------------------------

        sales_person_id = frappe.db.get_value(
            "Sales Person",
            {"employee": employee_id},
            "name"
        )

        if not sales_person_id:
            return api_response(
                False,
                "Sales Person not found for employee"
            )

        # -------------------------
        # FETCH TRACKING IDS
        # -------------------------

        tracking_data = frappe.db.sql("""
            SELECT DISTINCT
                iptl.tracking_id,
                si.name AS invoice_id,
                si.customer AS customer_id,
                si.customer_name,
                sii.sales_order AS order_id,
                c.mobile_no

            FROM `tabSales Team` st

            INNER JOIN `tabSales Invoice Item` sii
                ON sii.sales_order = st.parent

            INNER JOIN `tabSales Invoice` si
                ON si.name = sii.parent

            INNER JOIN `tabCustomer` c
                ON c.name = si.customer

            INNER JOIN `tabIndian Post Tracking Log` iptl
                ON iptl.reference_name = si.name

            WHERE st.sales_person = %(sales_person)s
            AND si.docstatus = 1

            AND IFNULL(si.custom_dispatch_status, '') NOT IN (
                    'Delivered',
                    'CANCELLED',
                    'REFUNDED'
            )

            AND IFNULL(iptl.tracking_id, '') != ''

            ORDER BY si.posting_date DESC
        """, {
            "sales_person": sales_person_id
        }, as_dict=True)

        return api_response(
            True,
            "Tracking IDs fetched successfully",
            tracking_data
        )

    except Exception:
        frappe.log_error(
            frappe.get_traceback(),
            "get_indian_post_tracking_ids_error"
        )
        return api_response(
            False,
            "Failed to fetch tracking IDs"
        )

