import math
import frappe
from frappe.utils import cint, pretty_date
from bs4 import BeautifulSoup
def clean_text(value):
    if not value:
        return ""

    # Remove extra spaces
    value = " ".join(str(value).split())

    # Convert to proper title case
    return value.title()

@frappe.whitelist()
@validate_method(methods=["GET", "POST"])
def get_order_remarks(
    sales_order=None,
    page=1,
    page_size=20
):

    try:

        # -------------------------
        # VALIDATION
        # -------------------------

        if not sales_order:
            return api_response(False, "Sales Order is required")

        # -------------------------
        # CHECK SALES ORDER EXISTS
        # -------------------------

        if not frappe.db.exists("Sales Order", sales_order):
            return api_response(False, "Sales Order not found")

        # -------------------------
        # PAGINATION
        # -------------------------

        page = cint(page or 1)
        page_size = cint(page_size or 20)

        if page < 1:
            page = 1

        if page_size < 1:
            page_size = 20

        start = (page - 1) * page_size

        # -------------------------
        # FILTERS
        # -------------------------

        filters = [
            ["Comment", "reference_doctype", "=", "Sales Order"],
            ["Comment", "reference_name", "=", sales_order],
            ["Comment", "comment_type", "=", "Comment"],
        ]

        # -------------------------
        # TOTAL COUNT
        # -------------------------

        total_records = frappe.db.count(
            "Comment",
            filters=filters
        )

        total_pages = math.ceil(
            total_records / page_size
        ) if page_size else 1

        # -------------------------
        # FETCH REMARKS
        # -------------------------

        remarks = frappe.get_all(
            "Comment",
            filters=filters,
            fields=[
                "name",
                "content as comment",
                "comment_by",
                "comment_email",
                "creation",
            ],
            order_by="creation desc",
            start=start,
            page_length=page_size
        )

        # -------------------------
        # FORMAT RESPONSE
        # -------------------------

        for row in remarks:

            user_image = frappe.db.get_value(
                "User",
                row.comment_email,
                "user_image",
                cache=True
            )
            row['comment_by'] = clean_text(row.get('comment_by'))
            row['name'] = clean_text(row.get('comment_by'))
            row["user_image"] =  get_url(user_image) if user_image else ""

            row["commented"] = pretty_date(
                row.creation
            )
            raw_comment = row.comment or ""

            row["comment"] = BeautifulSoup(
                raw_comment,
                "html.parser"
            ).get_text(
                separator=" ",
                strip=True
            )
            row["created_time"] = (
                row.creation.strftime("%I:%M %p")
            )

            row["created_date"] = (
                row.creation.strftime("%d-%m-%Y")
            )

        # -------------------------
        # RESPONSE
        # -------------------------

        return api_response(
            True,
            "Order remarks fetched successfully",
            {
                "total": total_records,
                "page": page,
                "page_size": page_size,
                "total_pages": total_pages,
                "data": remarks
            }
        )

    except Exception:
        frappe.log_error(frappe.get_traceback(),"get_order_remarks_error")
        return api_response(False,"Failed to fetch order remarks")
@frappe.whitelist()
def get_brand_ambassador_dashboard(
    from_date=None,
    to_date=None,
    brand_ambassador=None
):
    try:

        user = frappe.session.user

        # -----------------------------------
        # Conditions
        # -----------------------------------

        conditions = [
            "ba.warrior = %(user)s"
        ]

        params = {
            "user": user,
            "from_date": from_date,
            "to_date": to_date
        }

        # -----------------------------------
        # Brand Ambassador Date Filter
        # -----------------------------------

        if from_date and to_date:

            conditions.append("""
                (
                    ba.joining_date
                    BETWEEN %(from_date)s
                    AND %(to_date)s
                )
            """)

        # -----------------------------------
        # Brand Ambassador Filter
        # -----------------------------------

        if brand_ambassador:

            conditions.append("""
                ba.name = %(brand_ambassador)s
            """)

            params["brand_ambassador"] = brand_ambassador

        where_clause = " AND ".join(conditions)

        # -----------------------------------
        # Summary Dashboard
        # -----------------------------------

        summary = frappe.db.sql(f"""
            SELECT

                COUNT(DISTINCT so.name)
                    AS order_count,

                IFNULL(
                    SUM(DISTINCT so.grand_total),
                    0
                ) AS order_amount,

                -- Sales Invoice Amount

                IFNULL(
                    SUM(
                        DISTINCT CASE
                            WHEN si.is_return = 0
                            THEN si.grand_total
                            ELSE 0
                        END
                    ),
                    0
                ) AS invoice_amount,

                -- Received Amount

                IFNULL(
                    SUM(
                        DISTINCT IFNULL(
                            so.advance_paid,
                            0
                        )
                    ),
                    0
                ) AS received_amount,

                -- Return Invoice Amount / Credit Note

                IFNULL(
                    SUM(
                        DISTINCT CASE
                            WHEN si.is_return = 1
                            THEN ABS(si.grand_total)
                            ELSE 0
                        END
                    ),
                    0
                ) AS return_invoice_amount,

                COUNT(DISTINCT ba.name)
                    AS brand_ambassador_count

            FROM `tabBrand Ambassador` ba

            LEFT JOIN `tabSales Order` so
                ON (
                    so.custom_brand_ambassador = ba.name
                    AND so.docstatus = 1

                    -- Only SO having Brand Ambassador

                    AND IFNULL(
                        so.custom_brand_ambassador,
                        ''
                    ) != ''

                    -- Sales Order Date Filter

                    AND (
                        %(from_date)s IS NULL
                        OR %(to_date)s IS NULL
                        OR so.transaction_date
                            BETWEEN %(from_date)s
                            AND %(to_date)s
                    )
                )

            LEFT JOIN `tabSales Invoice Item` sii
                ON sii.sales_order = so.name

            LEFT JOIN `tabSales Invoice` si
                ON si.name = sii.parent
                AND si.docstatus = 1

            WHERE {where_clause}

        """, params, as_dict=True)[0]

        # -----------------------------------
        # Brand Ambassador Wise Dashboard
        # -----------------------------------

        brand_ambassador_data = frappe.db.sql(f"""
            SELECT
                ba.name
                    AS brand_ambassador,
                ba.customer,
                c.customer_name,
                COUNT(DISTINCT so.name)
                    AS order_count,
                IFNULL(
                    SUM(DISTINCT so.grand_total),
                    0
                ) AS order_amount,

                -- Invoice Amount

                IFNULL(
                    SUM(
                        DISTINCT CASE
                            WHEN si.is_return = 0
                            THEN si.grand_total
                            ELSE 0
                        END
                    ),
                    0
                ) AS invoice_amount,

                -- Received Amount

                IFNULL(
                    SUM(
                        DISTINCT IFNULL(
                            so.advance_paid,
                            0
                        )
                    ),
                    0
                ) AS received_amount,

                -- Return Invoice Amount

                IFNULL(
                    SUM(
                        DISTINCT CASE
                            WHEN si.is_return = 1
                            THEN ABS(si.grand_total)
                            ELSE 0
                        END
                    ),
                    0
                ) AS return_invoice_amount

            FROM `tabBrand Ambassador` ba

            LEFT JOIN `tabCustomer` c
                ON c.name = ba.customer

            LEFT JOIN `tabSales Order` so
                ON (
                    so.custom_brand_ambassador = ba.name
                    AND so.docstatus = 1

                    -- Only SO having Brand Ambassador

                    AND IFNULL(
                        so.custom_brand_ambassador,
                        ''
                    ) != ''

                    -- Sales Order Date Filter

                    AND (
                        %(from_date)s IS NULL
                        OR %(to_date)s IS NULL
                        OR so.transaction_date
                            BETWEEN %(from_date)s
                            AND %(to_date)s
                    )
                )

            LEFT JOIN `tabSales Invoice Item` sii
                ON sii.sales_order = so.name

            LEFT JOIN `tabSales Invoice` si
                ON si.name = sii.parent
                AND si.docstatus = 1

            WHERE {where_clause}

            GROUP BY ba.name

            ORDER BY order_amount DESC

        """, params, as_dict=True)

        frappe.log_error(
            message=f"params: {params} and where_clause: {where_clause}",
            title="Brand Ambassador Dashboard Query"
        )

        # -----------------------------------
        # Top Brand Ambassador
        # -----------------------------------

        top_brand_ambassador = (
            brand_ambassador_data[0]
            if brand_ambassador_data
            else {}
        )

        # -----------------------------------
        # Final Response
        # -----------------------------------

        return {
            "success": True,
            "message": "Brand Ambassador dashboard fetched successfully",
            "data": {
                "summary": summary,
                "top_brand_ambassador": top_brand_ambassador,
                "brand_ambassador_data": brand_ambassador_data
            }
        }

    except Exception:

        frappe.log_error(
            frappe.get_traceback(),
            "get_brand_ambassador_dashboard"
        )

        return {
            "success": False,
            "message": "Failed to fetch dashboard",
            "data": None
        }


        
import frappe

@frappe.whitelist()
def enqueue_bank_transfer_batches():
    frappe.enqueue(
        "warrior.apis.sales_order.update_approved_amount_batch",
        queue="long",
        timeout=3600)        

def update_approved_amount_batch(batch_size=500):
    start = 0

    while True:
        # 🔍 Fetch batch
        records = frappe.get_all(
            "Bank Transfer Request",
            filters={
                "approved_amount":0,
            },
            fields=["name", "amount"],
            limit_start=start,
            limit_page_length=batch_size
        )

        if not records:
            print("✅ Done updating all records")
            break

        for r in records:
            if r.amount and r.amount > 0:
                frappe.db.set_value(
                    "Bank Transfer Request",
                    r.name,
                    "approved_amount",
                    r.amount
                )

        frappe.db.commit()  # 🔥 commit per batch
        print(f"✅ Updated batch starting at {start}")

        start += batch_size
        


